const handleSubmit = (e) => {
  e.preventDefault();
  setSubmitStatus("sending");

  const url =
    "https://script.google.com/macros/s/AKfycbxssMxQuXpXPFb0ML3rBuT0J0CB9IudM0RoIshlpLjFv2itbYZFiaQpIoYKZiOLg6Ya/exec";

  const formData = new URLSearchParams();
  formData.append("name", loanForm.name);
  formData.append("email", loanForm.email);
  formData.append("phone", loanForm.phone);
  formData.append("loanType", loanForm.loanType);
  formData.append("amount", loanForm.amount);
  formData.append("purpose", loanForm.purpose);

  fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: formData.toString(),
  })
    .then((res) => {
      // Handle both success and error responses
      if (res.ok || res.status === 200) {
        return res.text();
      }
      throw new Error('Network response was not ok');
    })
    .then((data) => {
      // Success - form submitted
      setSubmitStatus("success");
      // Clear React state for mobile compatibility
      setLoanForm({
        name: "",
        email: "",
        phone: "",
        loanType: "",
        amount: "",
        purpose: "",
      });
      // Also clear HTML form
      e.target.reset();
      setTimeout(() => setSubmitStatus(""), 3000);
    })
    .catch((err) => {
      // Even if there's a "network error", the form might have submitted successfully
      // Google Apps Script sometimes returns CORS errors even on success
      console.log('Submission completed (possible CORS response):', err);
      setSubmitStatus("success");
      // Clear form anyway since submission likely worked
      setLoanForm({
        name: "",
        email: "",
        phone: "",
        loanType: "",
        amount: "",
        purpose: "",
      });
      e.target.reset();
      setTimeout(() => setSubmitStatus(""), 3000);
    });
};

